2	
3	buildscript {
4	    
5	    repositories {
6	        google()
7	        jcenter()
8	        
9	    }
10	    dependencies {
11	        classpath 'com.android.tools.build:gradle:3.6.3'
12	
13	        // NOTE: Do not place your application dependencies here; they belong
14	        // in the individual module build.gradle files
